{"operationName":"pageHeaders","variables":{},"query":"query pageHeaders {
  pageHeaders {
    id
    type
    referenceId
    headerText
    headerFile {
      id
      name
      url
      alternativeContent
      __typename
    }
    __typename
  }
}
"}

{"operationName":"getGalleryGroup","variables":{"slug":"pictures"},"query":"query getGalleryGroup($slug: String!) {
  galleryGroup(slug: $slug) {
    id
    isAvailable
    name
    slug
    __typename
  }
}
"}

{"operationName":"galleriesV2","variables":{"paginationOptions":{"type":"OFFSET","offsetOptions":{"offset":0,"limit":12}},"filterOptions":{"galleryGroupSlug":"pictures"},"sortKey":"PUBLICATION_START_AT"},"query":"query galleriesV2($paginationOptions: PaginationOptionsInput!, $filterOptions: GalleryFilterOptionsInput, $sortKey: GallerySortKey) {
  galleriesV2(
    paginationOptions: $paginationOptions
    filterOptions: $filterOptions
    sortKey: $sortKey
  ) {
    pageInfo {
      endCursor
      hasNextPage
      hasPreviousPage
      startCursor
      __typename
    }
    edges {
      node {
        id
        name
        description
        releaseDay
        contents {
          id
          seq
          imagePresetUrl {
            ...GalleryImagePresetUrl
            __typename
          }
          contentFile {
            id
            name
            url
            __typename
          }
          __typename
        }
        talents {
          ...TalentTagFragment
          __typename
        }
        isViewable
        viewableScope {
          scopeType
          plans {
            id
            name
            metadata
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    totalCount
    __typename
  }
}

fragment TalentTagFragment on Talent {
  id
  parentId
  name
  __typename
}

fragment GalleryImagePresetUrl on GalleryImagePresetUrl {
  thumbnail
  small
  medium
  large
  xLarge
  original
  __typename
}
"}
